   196	function createClient(
   197		model: Model<"openai-responses">,
   198		context: Context,
   199		apiKey?: string,
   200		extraHeaders?: Record<string, string>,
   201		initiatorOverride?: MessageAttribution,
   202	): {
   203		client: OpenAI;
   204		copilotPremiumRequests: number | undefined;
   205		baseUrl: string | undefined;
   206	} {
   207		if (!apiKey) {
   208			if (!$env.OPENAI_API_KEY) {
   209				throw new Error(
   210					"OpenAI API key is required. Set OPENAI_API_KEY environment variable or pass it as an argument.",
   211				);
   212			}
   213			apiKey = $env.OPENAI_API_KEY;
   214		}
   215	
   216		const headers = { ...(model.headers ?? {}), ...(extraHeaders ?? {}) };
   217		let copilotPremiumRequests: number | undefined;
   218	
   219		let baseUrl = model.baseUrl;
   220		if (model.provider === "github-copilot") {
   221			const hasImages = hasCopilotVisionInput(context.messages);
   222			const copilot = buildCopilotDynamicHeaders({
   223				messages: context.messages,
   224				hasImages,
   225				premiumMultiplier: model.premiumMultiplier,
   226				headers,
   227				initiatorOverride,
   228			});
   229			Object.assign(headers, copilot.headers);
   230			copilotPremiumRequests = copilot.premiumRequests;
   231			baseUrl = resolveGitHubCopilotBaseUrl(model.baseUrl, apiKey) ?? model.baseUrl;
   232		}
   233		return {
   234			client: new OpenAI({
   235				apiKey,
   236				baseURL: baseUrl,
   237				dangerouslyAllowBrowser: true,
   238				maxRetries: 5,
   239				defaultHeaders: headers,
   240			}),
   241			copilotPremiumRequests,
   242			baseUrl,
   243		};
   244	}
