   343		if (model.provider === "openai" || model.provider === "azure" || model.provider === "github-copilot") return true;
   344	
   345		const baseUrl = model.baseUrl.toLowerCase();
   346		return (
   347			baseUrl.includes("api.openai.com") ||
   348			baseUrl.includes(".openai.azure.com") ||
   349			baseUrl.includes("models.inference.ai.azure.com")
   350		);
