   408	function convertTools(tools: Tool[], strictMode: boolean): OpenAITool[] {
   409		return tools.map(tool => {
   410			const strict = !NO_STRICT && strictMode && tool.strict !== false;
   411			const baseParameters = tool.parameters as unknown as Record<string, unknown>;
   412			const { schema: parameters, strict: effectiveStrict } = adaptSchemaForStrict(baseParameters, strict);
   413			return {
   414				type: "function",
   415				name: tool.name,
   416				description: tool.description || "",
   417				parameters,
   418				...(effectiveStrict && { strict: true }),
   419			} as OpenAITool;
   420		});
   421	}
