   594		// 2. Emit kept messages (from firstKeptEntryId up to compaction)
   595		// 3. Emit messages after compaction
   596		const messages: AgentMessage[] = [];
   597	
   598		const appendMessage = (entry: SessionEntry) => {
   599			if (entry.type === "message") {
   600				messages.push(entry.message);
   601			} else if (entry.type === "custom_message") {
   602				messages.push(
   603					createCustomMessage(
   604						entry.customType,
   605						entry.content,
   606						entry.display,
   607						entry.details,
   608						entry.timestamp,
   609						entry.attribution,
   610					),
   611				);
   612			} else if (entry.type === "branch_summary" && entry.summary) {
   613				messages.push(createBranchSummaryMessage(entry.summary, entry.fromId, entry.timestamp));
   614			}
   615		};
   616	
   617		if (compaction) {
   618			const providerPayload: ProviderPayload | undefined = (() => {
   619				const candidate = compaction.preserveData?.openaiRemoteCompaction;
   620				if (!candidate || typeof candidate !== "object") return undefined;
   621				const remote = candidate as { provider?: unknown; replacementHistory?: unknown };
   622				if (typeof remote.provider !== "string" || remote.provider.length === 0) return undefined;
   623				if (!Array.isArray(remote.replacementHistory)) return undefined;
   624				return {
   625					type: "openaiResponsesHistory",
   626					provider: remote.provider,
   627					items: remote.replacementHistory as Array<Record<string, unknown>>,
   628				};
   629			})();
   630			const remoteReplacementHistory = providerPayload?.items;
   631	
   632			// Emit summary first
   633			messages.push(
   634				createCompactionSummaryMessage(
   635					compaction.summary,
   636					compaction.tokensBefore,
   637					compaction.timestamp,
   638					compaction.shortSummary,
   639					providerPayload,
   640				),
   641			);
   642	
   643			// Find compaction index in path
   644			const compactionIdx = path.findIndex(e => e.type === "compaction" && e.id === compaction.id);
   645	
   646			if (!remoteReplacementHistory) {
   647				// Emit kept messages (before compaction, starting from firstKeptEntryId)
   648				let foundFirstKept = false;
   649				for (let i = 0; i < compactionIdx; i++) {
   650					const entry = path[i];
   651					if (entry.id === compaction.firstKeptEntryId) {
   652						foundFirstKept = true;
   653					}
   654					if (foundFirstKept) {
   655						appendMessage(entry);
   656					}
   657				}
   658			}
   659	
   660			// Emit messages after compaction
   661			for (let i = compactionIdx + 1; i < path.length; i++) {
   662				const entry = path[i];
   663				appendMessage(entry);
   664			}
   665		} else {
   666			// No compaction - emit all messages, handle branch summaries and custom messages
   667			for (const entry of path) {
   668				appendMessage(entry);
   669			}
   670		}

